func  (this *OxfunCore) ParseMarkets(markets any) any  {
    var marketIds any = []any{}
    var result any = []any{}
    for i := 0; IsLessThan(i, GetArrayLength(markets)); i++ {
        var market any = GetValue(markets, i)
        var marketId any = this.SafeString(market, "marketCode")
        if !IsTrue((this.InArray(marketId, marketIds))) {
            AppendToArray(&marketIds, marketId)
            AppendToArray(&result, this.ParseMarket(market))
        }
    }
    return result
}
func  (this *OxfunCore) ParseMarket(market any) any  {
    var id any = this.SafeString(market, "marketCode", "")
    var parts any = Split(id, "-")
    var baseId any = this.SafeString(parts, 0)
    var quoteId any = this.SafeString(parts, 1)
    var base any = this.SafeCurrencyCode(baseId)
    var quote any = this.SafeCurrencyCode(quoteId)
    var symbol any = Add(Add(base, "/"), quote)
    var typeVar any = this.SafeStringLower(market, "type", "spot") // markets from v3/tickers are spot and have no type
    var settleId any = nil
    var settle any = nil
    var isFuture any =     (IsEqual(typeVar, "future")) // the exchange has only perpetual futures
    if IsTrue(isFuture) {
        typeVar = "swap"
        settleId = "OX"
        settle = this.SafeCurrencyCode("OX")
        symbol = Add(Add(symbol, ":"), settle)
    }
    var isSpot any = IsEqual(typeVar, "spot")
    return this.SafeMarketStructure(map[string]any {
        "id": id,
        "numericId": nil,
        "symbol": symbol,
        "base": base,
        "quote": quote,
        "settle": settle,
        "baseId": baseId,
        "quoteId": quoteId,
        "settleId": settleId,
        "type": typeVar,
        "spot": isSpot,
        "margin": false,
        "swap": isFuture,
        "future": false,
        "option": false,
        "active": true,
        "contract": isFuture,
        "linear": Ternary(IsTrue(isFuture), true, nil),
        "inverse": Ternary(IsTrue(isFuture), false, nil),
        "taker": GetValue(GetValue(this.Fees, "trading"), "taker"),
        "maker": GetValue(GetValue(this.Fees, "trading"), "maker"),
        "contractSize": Ternary(IsTrue(isFuture), 1, nil),
        "expiry": nil,
        "expiryDatetime": nil,
        "strike": nil,
        "optionType": nil,
        "precision": map[string]any {
            "amount": nil,
            "price": this.SafeNumber(market, "tickSize"),
        },
        "limits": map[string]any {
            "leverage": map[string]any {
                "min": nil,
                "max": nil,
            },
            "amount": map[string]any {
                "min": this.SafeNumber(market, "minSize"),
                "max": nil,
            },
            "price": map[string]any {
                "min": nil,
                "max": nil,
            },
            "cost": map[string]any {
                "min": nil,
                "max": nil,
            },
        },
        "created": this.SafeInteger(market, "listedAt"),
        "index": nil,
        "info": market,
    })
}
